def _is_item_active(item: dict) -> bool:
    return item.get('s') == 'active'


def _validate_timestamp(
    item: dict,
    index: int,
    cutoff: float
) -> tuple[bool, float | None, dict | None]:
    timestamp = item.get('ts')
    if timestamp is None:
        error = {'idx': index, 'msg': 'missing ts', 'id': item.get('id')}
        return (False, None, error)
    if timestamp > cutoff:
        return (False, None, None)
    return (True, timestamp, None)


def _cap_value(value: float, maximum: float, item: dict) -> float:
    if value > maximum:
        item['capped'] = True
        return maximum
    return value


def _check_minimum(value: float, minimum: float, item: dict, index: int) -> dict | None:
    if value < minimum:
        return {'idx': index, 'msg': 'below min', 'id': item.get('id'), 'val': value}
    return None


def _apply_multiplier_and_round(
    value: float,
    multiplier: float,
    should_round: bool,
    round_decimals: int
) -> float:
    value = value * multiplier
    if should_round:
        value = round(value, round_decimals)
