        minimum_error = _check_minimum(value, minimum_value, item, index)
        if minimum_error is not None:
            errors.append(minimum_error)
            continue

        value = _apply_multiplier_and_round(value, multiplier, should_round, round_decimals)

        results.append({
            'id': item.get('id'),
            'v': value,
            'ts': timestamp,
            'src': item.get('src', 'unknown'),
        })

    return results, errors
